transform_js:
const grouped = {};
rawData.rows.forEach(r => {
  if (!grouped[r.category]) grouped[r.category] = [];
  grouped[r.category].push(r.value);
});
const categories = Object.keys(grouped);
const boxData = [];
const outliers = [];
// 簡易な四分位数計算
categories.forEach((cat, index) => {
  const sorted = grouped[cat].sort((a, b) => a - b);
  const q1 = sorted[Math.floor(sorted.length * 0.25)];
  const median = sorted[Math.floor(sorted.length * 0.5)];
  const q3 = sorted[Math.floor(sorted.length * 0.75)];
  const iqr = q3 - q1;
  const minBound = q1 - 1.5 * iqr;
  const maxBound = q3 + 1.5 * iqr;

  let min = Infinity;
  let max = -Infinity;
  sorted.forEach(val => {
      if (val >= minBound && val <= maxBound) {
          if (val < min) min = val;
          if (val > max) max = val;
      } else {
          outliers.push([index, val]);
      }
  });
  // echarts の boxplot data 形式: [min, Q1, median, Q3, max]
  boxData.push([min, q1, median, q3, max]);
});
transformedData = { categories, boxData, outliers };

echarts_js:
option = {
  title: {
    text: 'Quality Variance (Boxplot)',
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    axisPointer: { type: 'shadow' }
  },
  grid: {
    left: '10%',
    right: '10%',
    bottom: '15%'
  },
  xAxis: {
    type: 'category',
    data: transformedData.categories,
    boundaryGap: true,
    nameGap: 30,
    splitArea: {
      show: true
    },
    axisLabel: { formatter: '{value}' }
  },
  yAxis: {
    type: 'value',
    name: 'Value',
    splitArea: { show: false }
  },
  series: [
    {
      name: 'boxplot',
      type: 'boxplot',
      data: transformedData.boxData,
      tooltip: {
        formatter: function (param) {
          return [
            'Experiment ' + param.name + ': ',
            'upper: ' + param.data[5],
            'Q3: ' + param.data[4],
            'median: ' + param.data[3],
            'Q1: ' + param.data[2],
            'lower: ' + param.data[1]
          ].join('<br/>');
        }
      }
    },
    {
      name: 'outlier',
      type: 'scatter',
      data: transformedData.outliers
    }
  ]
};
